// Memeware 7.3 - MultiAura.java (C18 spectate attack):
// After target selection, teleport to each target via C18
public void doSpectateAttack(Entity target) {
    // Teleport to target entity
    mc.thePlayer.sendQueue.addToSendQueue(
        new C18PacketSpectate(target.getUniqueID()));

    // Attack immediately after teleport
    mc.thePlayer.sendQueue.addToSendQueue(
        new C02PacketUseEntity(target, C02PacketUseEntity.Action.ATTACK));

    // Teleport back to self
    mc.thePlayer.sendQueue.addToSendQueue(
        new C18PacketSpectate(mc.thePlayer.getUniqueID()));
}

